import React, { useEffect, useState } from 'react';
import { api } from '../api';
import { enqueue, getQueue, flushQueue } from '../offline/queue';

export default function Dashboard() {
  const [categories, setCategories] = useState([]);
  const [listings, setListings] = useState([]);
  const [queueSize, setQueueSize] = useState(getQueue().length);
  const [result, setResult] = useState('');

  useEffect(() => {
    api('/categories').then(setCategories).catch(() => {});
    api('/listings').then(setListings).catch(() => {});
  }, []);

  const makeBooking = async (listingId) => {
    const payload = {
      listingId,
      couponCode: 'OFFLINE10',
      startAt: new Date().toISOString(),
      endAt: new Date(Date.now() + 3600_000).toISOString(),
      odoStart: 100,
      odoEnd: 118,
    };

    if (!navigator.onLine) {
      enqueue({ type: 'booking', path: '/bookings', method: 'POST', payload });
      setQueueSize(getQueue().length);
      setResult('Offline: booking queued.');
      return;
    }

    const data = await api('/bookings', { method: 'POST', body: JSON.stringify(payload) });
    setResult(`Booking created: ${data.booking.id}`);
  };

  const syncNow = async () => {
    await flushQueue(async (item) => {
      await api(item.path, { method: item.method, body: JSON.stringify(item.payload) });
    });
    // RULES: no 3rd-party integrations in offline mode.
    // Email/SMS dispatch remains mocked and disabled in this offline suite.
    setQueueSize(getQueue().length);
    setResult('Offline queue synced.');
  };

  return (
    <div>
      <h2>FleetLease Dashboard</h2>
      <p>Offline queue: {queueSize}</p>
      <button onClick={syncNow}>Sync Queue</button>
      <h3>Categories</h3>
      <ul>{categories.map((c) => <li key={c.id}>{c.name}</li>)}</ul>
      <h3>Listings</h3>
      <ul>
        {listings.map((l) => (
          <li key={l.id}>
            {l.name} ({l.spu}/{l.sku}) <button onClick={() => makeBooking(l.id)}>Book</button>
          </li>
        ))}
      </ul>
      <p>{result}</p>
    </div>
  );
}
