func (h *Handler) CreateBooking(c echo.Context) error {
	var req struct {
		ListingID  string  `json:"listingId"`
		CouponCode string  `json:"couponCode"`
		StartAt    string  `json:"startAt"`
		EndAt      string  `json:"endAt"`
		OdoStart   float64 `json:"odoStart"`
		OdoEnd     float64 `json:"odoEnd"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	listing, ok := h.Store.GetListing(req.ListingID)
	if !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "listing not found"})
	}
	startAt, _ := time.Parse(time.RFC3339, req.StartAt)
	endAt, _ := time.Parse(time.RFC3339, req.EndAt)
	estimate := services.EstimateFare(h.Pricing, services.EstimateInput{StartAt: startAt, EndAt: endAt, OdoStart: req.OdoStart, OdoEnd: req.OdoEnd, Deposit: listing.Deposit})
	customerID, _ := c.Get("userID").(string)
	booking := models.Booking{ID: uuid.NewString(), CustomerID: customerID, ListingID: listing.ID, CouponCode: req.CouponCode, StartAt: startAt, EndAt: endAt, OdoStart: req.OdoStart, OdoEnd: req.OdoEnd, Status: "booked", EstimatedAmount: estimate.Total, DepositAmount: estimate.Deposit}
	h.Store.SaveBooking(booking)
	return c.JSON(http.StatusCreated, map[string]interface{}{"booking": booking, "estimate": estimate})
}

func (h *Handler) RedeemCoupon(c echo.Context) error {
	var req struct {
		Code      string `json:"code"`
		BookingID string `json:"bookingId"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	if ok := h.Store.MarkCouponUsed(req.Code, req.BookingID); !ok {
		return c.JSON(http.StatusConflict, map[string]string{"error": "coupon already redeemed"})
	}
	return c.JSON(http.StatusOK, map[string]string{"status": "provisional accepted"})
}

func (h *Handler) UpsertInspection(c echo.Context) error {
	var req struct {
		BookingID string                  `json:"bookingId"`
		Stage     string                  `json:"stage"`
		Items     []models.InspectionItem `json:"items"`
		Notes     string                  `json:"notes"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	if len(req.Items) == 0 {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "inspection items required"})
	}
	for _, item := range req.Items {
		if len(item.EvidenceIDs) == 0 {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "camera evidence required per checklist item"})
		}
	}
	prevHash := ""
	revisions := h.Store.ListInspections(req.BookingID)
	if len(revisions) > 0 {
		prevHash = revisions[len(revisions)-1].Hash
	}
	userID, _ := c.Get("userID").(string)
	now := time.Now().UTC()
	payload, _ := json.Marshal(req)
	hash := services.ChainHash(prevHash, string(payload), now)
	rev := models.InspectionRevision{RevisionID: uuid.NewString(), BookingID: req.BookingID, Stage: req.Stage, Items: req.Items, Notes: req.Notes, CreatedBy: userID, CreatedAt: now, PrevHash: prevHash, Hash: hash}
	h.Store.SaveInspection(req.BookingID, rev)
	return c.JSON(http.StatusCreated, rev)
}

func (h *Handler) AttachmentInit(c echo.Context) error {
	var req struct {
		BookingID   string `json:"bookingId"`
		Type        string `json:"type"`
		SizeBytes   int64  `json:"sizeBytes"`
		Checksum    string `json:"checksum"`
		Fingerprint string `json:"fingerprint"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	if req.Type == "photo" && req.SizeBytes > 10*1024*1024 {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "photo size exceeds 10MB"})
	}
	if req.Type == "video" && req.SizeBytes > 100*1024*1024 {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "video size exceeds 100MB"})
	}
	if existing, ok := h.Store.FindAttachmentByFingerprint(req.Fingerprint); ok {
		return c.JSON(http.StatusOK, map[string]interface{}{"deduplicated": true, "attachment": existing})
