	att := models.Attachment{ID: uuid.NewString(), BookingID: req.BookingID, Type: req.Type, SizeBytes: req.SizeBytes, Checksum: req.Checksum, Fingerprint: req.Fingerprint, Path: fmt.Sprintf("%s/%s.bin", h.Cfg.AttachmentDir, uuid.NewString())}
	h.Store.SaveAttachment(att)
	return c.JSON(http.StatusCreated, map[string]interface{}{"uploadId": att.ID, "path": att.Path, "checksum": att.Checksum})
}

