import React, { useEffect, useState } from 'react';
import { Sparkles, PlusCircle, RefreshCw } from 'lucide-react';
import { api } from '../api';
import VehicleCard from '../components/VehicleCard';
import { enqueue, getQueue } from '../offline/queue';

const updates = [
  'Captured inspection for Van SKU-X',
  'Coupon OFFLINE10 applied',
  'Reservation #2239 awaiting sync'
];

export default function BookingsPage({ onToast, onQueueChange }) {
  const [listings, setListings] = useState([]);
  const [status, setStatus] = useState('');
  const [syncing, setSyncing] = useState(false);

  useEffect(() => {
    api('/listings')
      .then(setListings)
      .catch(() => setStatus('Unable to reach API. Working offline?'));
  }, []);

  const handleBooking = async (listingId) => {
    const payload = {
      listingId,
      couponCode: 'OFFLINE10',
      startAt: new Date().toISOString(),
      endAt: new Date(Date.now() + 90 * 60000).toISOString(),
      odoStart: 120,
      odoEnd: 135
    };
    if (!navigator.onLine) {
      enqueue({ type: 'booking', path: '/bookings', method: 'POST', payload });
      onToast('Offline: booking queued for upload.');
      onQueueChange?.(getQueue().length);
      return;
    }
    try {
      const data = await api('/bookings', { method: 'POST', body: JSON.stringify(payload) });
      onToast(`Booking confirmed · ${data.booking.id}`);
    } catch (err) {
      onToast('Server error: booking saved locally.');
    }
  };

  const quickSync = () => {
    if (syncing) return;
    setSyncing(true);
    onToast('Starting sync...');
    window.dispatchEvent(new Event('syncQueue'));
    setTimeout(() => {
      setSyncing(false);
      onToast('Queue retried.');
    }, 3000);
  };

  return (
    <div className="space-y-6">
      <div className="grid sm:grid-cols-2 gap-4">
        {updates.map((text) => (
          <div key={text} className="flex items-center gap-3 text-sm text-slate-300 bg-white/5 border border-white/5 rounded-2xl p-4">
            <Sparkles className="h-4 w-4 text-teal-300" />
            <span>{text}</span>
          </div>
        ))}
      </div>
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">Inventory</h2>
        <button onClick={quickSync} className="flex items-center gap-2 text-sm text-brand">
          <RefreshCw className="h-4 w-4" />
          Refresh queue ({getQueue().length})
        </button>
      </div>
      <div className="grid lg:grid-cols-2 gap-4">
        {listings.map((listing) => (
          <VehicleCard key={listing.id} listing={listing} onBook={handleBooking} />
        ))}
        {!listings.length && (
          <p className="text-sm text-slate-400">Fetching listings from backend…</p>
        )}
      </div>
      {status && <p className="text-sm text-amber-300">{status}</p>}
    </div>
  );
}
