import React, { useEffect, useMemo, useState } from 'react';
import ReactDOM from 'react-dom/client';
import { CalendarDays, ClipboardList, Dashboard, ShieldCheck } from 'lucide-react';
import Login from './pages/Login';
import Layout from './components/Layout';
import Overview from './pages/Overview';
import BookingsPage from './pages/BookingsPage';
import InspectionPage from './pages/InspectionPage';
import AdminPage from './pages/AdminPage';
import { api, me, logout } from './api';
import { flushQueue, getQueue } from './offline/queue';
import './styles.css';

function App() {
  const [profile, setProfile] = useState(() => {
    const stored = localStorage.getItem('user');
    return stored ? JSON.parse(stored) : null;
  });
  const [queueSize, setQueueSize] = useState(getQueue().length);
  const [active, setActive] = useState('Overview');
  const [loadingProfile, setLoadingProfile] = useState(!!localStorage.getItem('token'));

  const fetchProfile = async () => {
    try {
      const data = await me();
      setProfile(data);
      localStorage.setItem('user', JSON.stringify(data));
      setQueueSize(getQueue().length);
    } catch (err) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      setProfile(null);
    } finally {
      setLoadingProfile(false);
    }
  };

  useEffect(() => {
    if (localStorage.getItem('token')) {
      fetchProfile();
    } else {
      setLoadingProfile(false);
    }
  }, []);

  const handleLogin = () => fetchProfile();

  const handleLogout = async () => {
    try {
      await logout();
    } finally {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      setProfile(null);
      setActive('Overview');
    }
  };

  const navItems = useMemo(() => {
    const roles = profile?.roles || [];
    const hasRole = (role) => roles.includes(role);
    const items = [{ label: 'Overview', icon: Dashboard }];
    if (hasRole('customer') || hasRole('provider')) {
      items.push({ label: 'Bookings', icon: CalendarDays });
    }
    if (hasRole('provider') || hasRole('csa')) {
      items.push({ label: 'Inspections', icon: ClipboardList });
    }
    if (hasRole('admin')) {
      items.push({ label: 'Admin', icon: ShieldCheck });
    }
    return items;
  }, [profile]);

  useEffect(() => {
    if (navItems.length && !navItems.some((item) => item.label === active)) {
      setActive(navItems[0].label);
    }
  }, [active, navItems]);

  const syncQueue = async () => {
    try {
      await flushQueue(async (item) => {
        await api(item.path, { method: item.method, body: JSON.stringify(item.payload) });
      });
      setQueueSize(getQueue().length);
    } catch (err) {
      setQueueSize(getQueue().length);
    }
  };

  if (loadingProfile) {
    return <div className="min-h-screen flex items-center justify-center text-slate-300">Loading profile…</div>;
  }

  if (!profile) {
    return <Login onLoggedIn={handleLogin} />;
  }

  const pages = {
    Overview: <Overview queueSize={queueSize} onSync={syncQueue} onOpenComplaint={() => alert('Complaint workflow coming soon.')} />,
    Bookings: <BookingsPage onToast={(message) => alert(message)} onQueueChange={setQueueSize} />,
    Inspections: <InspectionPage />,
    Admin: <AdminPage />
  };

  return (
    <Layout navItems={navItems} active={active} onNavigate={setActive} user={profile} onLogout={handleLogout}>
      {pages[active] || <Overview queueSize={queueSize} onSync={syncQueue} onOpenComplaint={() => alert('Complaint workflow coming soon.')} />}
    </Layout>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App />);
