		}
		hash, _ := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
		encGovID, _ := services.EncryptAES256([]byte(cfg.EncryptionKey), govID)
		u := models.User{ID: uuid.NewString(), Username: username, PasswordHash: string(hash), Roles: roles, GovernmentIDEnc: services.MaskSensitive(encGovID)}
