	}
	f, err := os.OpenFile(att.Path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to store chunk"})
	}
	defer f.Close()
	if _, err = f.Write(chunk); err != nil {
