	if !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "upload not found"})
	}
	booking, ok := h.Store.GetBooking(att.BookingID)
	if !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "booking not found"})
