func (h *Handler) AdminCreateListing(c echo.Context) error {
	var req struct {
		CategoryID    string  `json:"categoryId"`
		ProviderID    string  `json:"providerId"`
		SPU           string  `json:"spu"`
		SKU           string  `json:"sku"`
		Name          string  `json:"name"`
		IncludedMiles float64 `json:"includedMiles"`
		Deposit       float64 `json:"deposit"`
		Available     bool    `json:"available"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	if strings.TrimSpace(req.CategoryID) == "" || strings.TrimSpace(req.Name) == "" || strings.TrimSpace(req.SPU) == "" || strings.TrimSpace(req.SKU) == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "categoryId, name, spu and sku are required"})
	}
	if _, ok := h.Store.GetCategory(req.CategoryID); !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "category not found"})
	}
	if req.ProviderID != "" {
		u, ok := h.Store.GetUserByID(req.ProviderID)
		if !ok || !hasRole(u.Roles, models.RoleProvider) {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "providerId must reference provider user"})
		}
	}
	listing := models.Listing{ID: uuid.NewString(), CategoryID: req.CategoryID, ProviderID: req.ProviderID, SPU: req.SPU, SKU: req.SKU, Name: req.Name, IncludedMiles: req.IncludedMiles, Deposit: req.Deposit, Available: req.Available}
	h.Store.SaveListing(listing)
	return c.JSON(http.StatusCreated, listing)
}

func (h *Handler) AdminBulkListings(c echo.Context) error {
	var req struct {
		ListingIDs []string `json:"listingIds"`
		Available  *bool    `json:"available"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	if len(req.ListingIDs) == 0 || req.Available == nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "listingIds and available are required"})
	}
	updated := 0
	for _, id := range req.ListingIDs {
		listing, ok := h.Store.GetListing(id)
		if !ok {
			continue
		}
		listing.Available = *req.Available
		h.Store.SaveListing(listing)
		updated++
	}
	return c.JSON(http.StatusOK, map[string]int{"updated": updated})
}

func (h *Handler) AdminSearchListings(c echo.Context) error {
	q := strings.ToLower(strings.TrimSpace(c.QueryParam("q")))
	items := h.Store.ListListings()
	if q == "" {
		return c.JSON(http.StatusOK, items)
	}
	out := make([]models.Listing, 0)
	for _, item := range items {
		target := strings.ToLower(item.Name + " " + item.SPU + " " + item.SKU)
		if strings.Contains(target, q) {
			out = append(out, item)
		}
	}
	return c.JSON(http.StatusOK, out)
}

