		Channel string `json:"channel"`
		Enabled bool   `json:"enabled"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	channel := strings.ToLower(strings.TrimSpace(req.Channel))
	switch channel {
	case "", "in_app", "email", "sms":
	default:
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "channel must be in_app, email, or sms"})
	}
	if channel == "" {
		channel = "in_app"
	}
	createdBy, _ := c.Get("userID").(string)
	template := models.NotificationTemplate{ID: uuid.NewString(), Name: strings.TrimSpace(req.Name), Title: strings.TrimSpace(req.Title), Body: strings.TrimSpace(req.Body), Channel: channel, Enabled: req.Enabled, CreatedBy: createdBy, ModifiedAt: time.Now().UTC()}
	h.Store.SaveNotificationTemplate(template)
