func (h *Handler) AdminSendNotification(c echo.Context) error {
	var req struct {
		TemplateID string `json:"templateId"`
		UserID     string `json:"userId"`
	}
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	template, ok := h.Store.GetNotificationTemplate(req.TemplateID)
	if !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "template not found"})
	}
	if _, ok := h.Store.GetUserByID(req.UserID); !ok {
		return c.JSON(http.StatusNotFound, map[string]string{"error": "target user not found"})
	}
	status := "delivered"
	if template.Channel == "email" || template.Channel == "sms" {
		// RULES: no 3rd-party integrations in offline mode.
		status = "disabled_offline"
	}
	n := models.Notification{ID: uuid.NewString(), UserID: req.UserID, TemplateID: template.ID, Title: template.Title, Body: template.Body, Status: status, Attempts: 1, Fingerprint: template.ID + ":" + req.UserID, DeliveredAt: time.Now().UTC()}
	h.Store.SaveNotification(n)
	return c.JSON(http.StatusCreated, n)
}

func (h *Handler) AdminRetryNotifications(c echo.Context) error {
	items := h.Store.ListAllNotifications()
	retried := 0
	delivered := 0
	for _, item := range items {
		if item.Status == "delivered" {
			continue
		}
		item.Attempts++
		channel := "in_app"
		if item.TemplateID != "" {
			if template, ok := h.Store.GetNotificationTemplate(item.TemplateID); ok {
				channel = template.Channel
			}
		}
		if channel == "in_app" {
			item.Status = "delivered"
			item.DeliveredAt = time.Now().UTC()
			delivered++
		} else {
			// RULES: no 3rd-party integrations in offline mode.
			item.Status = "disabled_offline"
		}
		h.Store.SaveNotification(item)
		retried++
	}
	return c.JSON(http.StatusOK, map[string]int{"retried": retried, "delivered": delivered})
}

