func (h *Handler) Login(c echo.Context) error {
	var req loginRequest
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid payload"})
	}
	user, ok := h.Store.GetUserByUsername(strings.TrimSpace(req.Username))
	if !ok {
		h.Store.SaveAuthEvent(models.AuthEvent{ID: uuid.NewString(), Username: strings.TrimSpace(req.Username), IP: c.RealIP(), EventType: "login_failed_unknown_user", CreatedAt: time.Now().UTC()})
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "invalid credentials"})
	}
	if time.Now().UTC().Before(user.LockedUntil) {
		h.Store.SaveAuthEvent(models.AuthEvent{ID: uuid.NewString(), UserID: user.ID, Username: user.Username, IP: c.RealIP(), EventType: "login_blocked_lockout", CreatedAt: time.Now().UTC()})
		return c.JSON(http.StatusLocked, map[string]string{"error": "account locked for 15 minutes"})
	}
	if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.Password)); err != nil {
		user.FailedAttempts++
		if user.FailedAttempts >= 5 {
			user.LockedUntil = time.Now().UTC().Add(15 * time.Minute)
			user.FailedAttempts = 0
		}
		h.Store.SaveUser(user)
		h.Store.SaveAuthEvent(models.AuthEvent{ID: uuid.NewString(), UserID: user.ID, Username: user.Username, IP: c.RealIP(), EventType: "login_failed_invalid_password", CreatedAt: time.Now().UTC()})
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "invalid credentials"})
	}
	if user.TOTPEnabled && !services.ValidateTOTPCode(user.TOTPSecret, req.TOTPCode) {
		h.Store.SaveAuthEvent(models.AuthEvent{ID: uuid.NewString(), UserID: user.ID, Username: user.Username, IP: c.RealIP(), EventType: "login_failed_invalid_totp", CreatedAt: time.Now().UTC()})
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "invalid TOTP code"})
	}
	user.FailedAttempts = 0
	h.Store.SaveUser(user)
	token, session, err := h.AuthSvc.IssueToken(user)
	if err != nil {
		h.Logger.Error("failed to issue token", "err", err)
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to issue token"})
	}
	h.Store.SaveAuthEvent(models.AuthEvent{ID: uuid.NewString(), UserID: user.ID, Username: user.Username, IP: c.RealIP(), EventType: "login_success", CreatedAt: time.Now().UTC()})
