package middleware

import (
	"net"
	"net/http"

	"github.com/labstack/echo/v4"
)

func AdminIPAllowlist(cidrs []string) echo.MiddlewareFunc {
	nets := []*net.IPNet{}
	for _, c := range cidrs {
		_, ipnet, err := net.ParseCIDR(c)
		if err == nil {
			nets = append(nets, ipnet)
		}
	}
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			ip := requestRemoteIP(c)
			if ip == nil {
				return c.JSON(http.StatusForbidden, map[string]string{"error": "unable to determine client IP"})
			}
			for _, n := range nets {
				if n.Contains(ip) {
					return next(c)
				}
			}
			return c.JSON(http.StatusForbidden, map[string]string{"error": "ip not allowlisted"})
		}
	}
}

func requestRemoteIP(c echo.Context) net.IP {
	host, _, err := net.SplitHostPort(c.Request().RemoteAddr)
	if err != nil {
		host = c.Request().RemoteAddr
	}
	return net.ParseIP(host)
}
